query GetCampaignPacingByDateRange($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        budget
        pacingData {
          totalImpressions
          impressionGoal
          pace
          ctr
          roas
          budgetSpent
          budgetLeft
          daysLeft
        }
      }
    }
    aggregate {
      count
    }
  }
}

query GetCampaignPacing($campaignOrderId: ID!) {
  campaignOrdersConnection(where: { id: $campaignOrderId }) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        budget
        pacingData {
          id
          totalImpressions
          impressionGoal
          impressionsLeft
          budgetSpent
          totalBudget
          budgetLeft
          ctr
          roas
          pace
          daysLeft
          daysIntoFlight
        }
      }
    }
  }
}
